/**
 * Payload enviado por CRM (lib/mailer.js → postHoldedSyncToN8nWebhook):
 * - body directo o raw.body (según proxy)
 * - event: holded_sync_approval_request | holded_sync_digest | holded_sync_applied
 * - to, subject, html, text?, meta, appBaseUrl, source, ts
 */
const raw = $input.first().json;
const d = raw.body !== undefined && raw.body !== null && typeof raw.body === 'object'
  ? raw.body
  : raw;

const event = String(d.event || '').trim();
const to = String(d.to || '').trim();
const subject = String(d.subject || 'CRM Gemavip · Sincronización Holded').trim();
let html = String(d.html || '').trim();

if (!to) {
  throw new Error('Falta destinatario (to). Revisa el POST desde el CRM.');
}

if (!html) {
  const t = String(d.text || '').trim();
  html = t
    ? '<pre style="font-family:Segoe UI,Roboto,Arial,sans-serif;padding:24px;font-size:14px;color:#1f2a44;white-space:pre-wrap;">' + t.replace(/&/g,'&amp;').replace(/</g,'&lt;') + '</pre>'
    : '<p style="padding:24px;font-family:Segoe UI,Roboto,Arial,sans-serif;color:#64748b;">(Sin cuerpo HTML; revisa la configuración del CRM.)</p>';
}

const etiquetaEvento = {
  holded_sync_approval_request: 'Decisión de sincronización (enlaces firmados)',
  holded_sync_digest: 'Resumen de clientes pendientes',
  holded_sync_applied: 'Sincronización aplicada'
}[event] || event || 'Notificación Holded';

const banner = '<table width="100%" cellpadding="0" cellspacing="0" style="margin:0 0 16px 0;background:linear-gradient(135deg,rgba(0,139,210,0.12) 0%,rgba(143,174,27,0.08) 100%);border-radius:10px;border:1px solid #e2e8f0;"><tr><td style="padding:12px 16px;font-size:12px;color:#475569;"><strong style="color:#0c143a;">CRM Gemavip</strong> · Holded · ' + etiquetaEvento + (d.ts ? '<br/><span style="color:#94a3b8;">' + String(d.ts) + '</span>' : '') + '</td></tr></table>';

const esDocCompleto = /^\s*<!DOCTYPE/i.test(html) || /^\s*<html/i.test(html);
const htmlFinal = esDocCompleto
  ? html
  : '<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;background:#f4f6f9;">' + banner + '<div style="max-width:640px;margin:0 auto;padding:0 12px 24px;">' + html + '</div></body></html>';

return [{
  json: {
    to,
    subject,
    html: htmlFinal,
    event,
    meta: d.meta || {}
  }
}];
